{
  "update": "update1",
  "action_items": [
    {
      "id": "U1-001",
      "description": "Update project/src/config.py so TRANSACTIONS_FILE points to transactions_v2.csv and FIELD_MAP maps revenue to order_value, not amount.",
      "owner": "Maya",
      "status": "not_started",
      "due": "2025-03-08"
    },
    {
      "id": "U1-002",
      "description": "Fix project/src/data_loader.py to remove the transaction_amount rename, load the v2 transaction schema by default, and preserve the channel column through loading and cleaning.",
      "owner": "Maya",
      "status": "not_started",
      "due": "2025-03-08"
    },
    {
      "id": "U1-003",
      "description": "Refresh tests to validate transactions_v2.csv, including order_value as the revenue field and channel as a required retained column.",
      "owner": "Jordan",
      "status": "not_started",
      "due": "2025-03-09"
    },
    {
      "id": "U1-004",
      "description": "Update project/docs/metrics_definitions.md to reference the v2 cleaned transaction artifact and recompute headline transaction metrics from data/processed/transactions_v2_clean.csv.",
      "owner": "Jordan",
      "status": "not_started",
      "due": "2025-03-09"
    },
    {
      "id": "U1-005",
      "description": "Clean stale v1 and transaction_amount references from README and meeting-note follow-up sections so onboarding docs match the clarified v2 schema.",
      "owner": "Sam",
      "status": "not_started",
      "due": "2025-03-10"
    },
    {
      "id": "U1-006",
      "description": "Review the schema-facing docs after the v2 updates and sign off that the source-of-truth guidance is consistent before the next stakeholder share-out.",
      "owner": "Alex",
      "status": "not_started",
      "due": "2025-03-10"
    }
  ]
}

